// BankApp.java
package com.example.bankapp;

import androidx.appcompat.app.AppCompatActivity;
import android.os.Bundle;
import android.widget.TextView;

public class BankApp extends AppCompatActivity {

    private TextView accountBalanceTextView;
    private double accountBalance = 0.0;

    @Override
    protected void onCreate(Bundle savedInstanceState) {
        super.onCreate(savedInstanceState);
        setContentView(R.layout.activity_main);

        accountBalanceTextView = findViewById(R.id.account_balance_textview);

        // Sample transactions
        performTransaction("Deposit", 100.0);
        performTransaction("Withdrawal", 50.0);
    }

    private void performTransaction(String transactionType, double amount) {
        if (transactionType.equals("Deposit")) {
            accountBalance += amount;
            System.out.println("Deposited: " + amount);
        } else if (transactionType.equals("Withdrawal")) {
            if (amount <= accountBalance) {
                accountBalance -= amount;
                System.out.println("Withdrew: " + amount);
            } else {
                System.out.println("Insufficient funds");
            }
        }

        updateAccountBalanceTextView();
    }

    private void updateAccountBalanceTextView() {
        runOnUiThread(() -> {
            accountBalanceTextView.setText(String.valueOf(accountBalance));
        });
    }
}